import styles from './AudioTrack.module.css';

function AudioTrack({ objects, clips, setClips }) {
    const queueObjects = objects.filter(obj => obj.queue > 0)

    const sounds = [{
        red: '../data/sounds/red',
        green: '../data/sounds/green',
        blue: '../data/sounds/blue',
        yellow: '../data/sounds/yellow'
    }]

    const clipsAmount = 15


    return (
        <div className={styles.audioTrack}>
            {Array.from({ length: clipsAmount }, (_, i) => {
                const object = queueObjects.find(o => o.queue === i + 1);

                return (<div
                    key={i}
                    className={styles.clip}
                    style={{
                        backgroundColor: queueObjects.find(
                            (object) => object.queue === i + 1,
                        )?.color,
                    }}
                >
                    <div
                        className={styles.queue}
                        style={{
                            backgroundColor:
                                queueObjects.find(
                                    (object) => object.queue === i + 1,
                                ) && '#1e1e1ebb',

                            borderRadius:
                                queueObjects.find((object) => object.queue === i + 1)
                                    ?.radius === '50%'
                                    ? '100%'
                                    : '5%',
                        }}
                    >
                        <p>{i + 1}</p>
                    </div>
                </div>
                );
            })}
        </div>
    );
}

export default AudioTrack;
